code = """import pandas as pd
import json

# Load the filtered business data
filtered_business_data = json.loads(locals()['var_function-call-1601742060428775946'])
df_filtered_business = pd.DataFrame(filtered_business_data)

# Load the review data from the file
with open(locals()['var_function-call-13445225897142383132'], 'r') as f:
    review_data = json.load(f)

df_review = pd.DataFrame(review_data)

# Convert 'rating' column to numeric, handling potential errors
df_review['rating'] = pd.to_numeric(df_review['rating'], errors='coerce')

# Calculate the average rating for each business
df_average_ratings = df_review.groupby('gmap_id')['rating'].mean().reset_index()
df_average_ratings.rename(columns={'rating': 'average_rating'}, inplace=True)

# Merge the filtered business data with average ratings
df_merged = pd.merge(df_filtered_business, df_average_ratings, on='gmap_id', how='inner')

# Sort by average rating in descending order and select top 5
df_top_5 = df_merged.sort_values(by='average_rating', ascending=False).head(5)

# Select the required columns and format the output
result = df_top_5[['name', 'hours', 'average_rating']].to_json(orient='records')

print('__RESULT__:')
print(result)"""

